using BgControls.Windows.Controls.PropertyGrid.Attributes;using BgControls.Windows.Automation.Peers;using System.Linq.Expressions;using System.Windows.Automation.Peers;using BgControls.Core.Utilities;namespace BgControls.Windows.Controls.PropertyGrid;/// <summary>/// Base class of CustomPropertyItem./// </summary>[TemplatePart(Name = PropertyGrid.PART_PropertyItemsControl, Type = typeof(PropertyItemsControl))][TemplatePart(Name = PART_ValueContainer, Type = typeof(ContentControl))]public abstract class PropertyItemBase : Control, IPropertyContainer, INotifyPropertyChanged{    private const string PART_ValueContainer = "PART_ValueContainer";    private const int MaxSubLevelSearch = 10;    /// <summary>    /// Identifies the AdvancedOptionsIcon dependency property.    /// </summary>    public static readonly DependencyProperty AdvancedOptionsIconProperty =        DependencyProperty.Register("AdvancedOptionsIcon", typeof(ImageSource), typeof(PropertyItemBase), new UIPropertyMetadata(null));    /// <summary>    /// Identifies the AdvancedOptionsTooltip dependency property.    /// </summary>    public static readonly DependencyProperty AdvancedOptionsTooltipProperty =        DependencyProperty.Register("AdvancedOptionsTooltip", typeof(object), typeof(PropertyItemBase), new UIPropertyMetadata(null));    /// <summary>    /// Identifies the DefinitionKey dependency property.    /// </summary>    public static readonly DependencyProperty DefinitionKeyProperty =        DependencyProperty.Register("DefinitionKey", typeof(object), typeof(PropertyItemBase), new UIPropertyMetadata(null, OnDefinitionKeyChanged));    /// <summary>    /// Identifies the Description dependency property.    /// </summary>    public static readonly DependencyProperty DescriptionProperty =        DependencyProperty.Register("Description", typeof(string), typeof(PropertyItemBase), new UIPropertyMetadata(null));    /// <summary>    /// Identifies the DisplayName dependency property.    /// </summary>    public static readonly DependencyProperty DisplayNameProperty =        DependencyProperty.Register("DisplayName", typeof(string), typeof(PropertyItemBase), new UIPropertyMetadata(null));    /// <summary>    /// Identifies the Editor dependency property.    /// </summary>    public static readonly DependencyProperty EditorProperty =        DependencyProperty.Register("Editor", typeof(FrameworkElement), typeof(PropertyItemBase), new UIPropertyMetadata(null, OnEditorChanged));    /// <summary>I    /// dentifies the HighlightedText dependency property.    /// </summary>    public static readonly DependencyProperty HighlightedTextProperty =        DependencyProperty.Register("HighlightedText", typeof(string), typeof(PropertyItemBase), new UIPropertyMetadata(null));    /// <summary>    /// Identifies the IsExpanded dependency property.    /// </summary>    public static readonly DependencyProperty IsExpandedProperty =        DependencyProperty.Register("IsExpanded", typeof(bool), typeof(PropertyItemBase), new UIPropertyMetadata(false, OnIsExpandedChanged));    /// <summary>    /// Identifies the IsExpandable dependency property.    /// </summary>    public static readonly DependencyProperty IsExpandableProperty =        DependencyProperty.Register("IsExpandable", typeof(bool), typeof(PropertyItemBase), new UIPropertyMetadata(false));    /// <summary>    /// Identifies the IsSelected dependency property.    /// </summary>    public static readonly DependencyProperty IsSelectedProperty =        DependencyProperty.Register("IsSelected", typeof(bool), typeof(PropertyItemBase), new UIPropertyMetadata(false, OnIsSelectedChanged));    /// <summary>    /// Identifies the WillRefreshPropertyGrid dependency property.    /// </summary>    public static readonly DependencyProperty WillRefreshPropertyGridProperty =        DependencyProperty.Register("WillRefreshPropertyGrid", typeof(bool), typeof(PropertyItemBase), new UIPropertyMetadata(false));    /// <summary>    /// Identifies the ItemSelectionChanged routed event.    /// </summary>    internal static readonly RoutedEvent ItemSelectionChangedEvent =       EventManager.RegisterRoutedEvent("ItemSelectionChangedEvent", RoutingStrategy.Bubble, typeof(RoutedEventHandler), typeof(PropertyItemBase));    static PropertyItemBase()    {        FrameworkElement.DefaultStyleKeyProperty.OverrideMetadata(            typeof(PropertyItemBase),            new FrameworkPropertyMetadata(typeof(PropertyItemBase)));    }    private ContentControl valueContainer;    private ContainerHelperBase containerHelper;    private IPropertyContainer? parentNode;    private List<KeyValuePair<string, PropertyItem>> dependsOnPropertyItemsList = new List<KeyValuePair<string, PropertyItem>>();    private List<VisibleToAttribute>? visibleToAttributes = new List<VisibleToAttribute>();    private List<EnableToAttribute>? enableToAttributes = new List<EnableToAttribute>();    private int? decimalPlaces;    private double? increment;    private double? maximum;    private double? minimum;    internal bool isExpandingNonPrimitiveTypes;    internal bool isPropertyGridCategorized;    internal bool isSortedAlphabetically = true;    /// <summary>    /// Initializes a new instance of the <see cref="PropertyItemBase"/> class.    /// </summary>    internal PropertyItemBase()    {        this.DataContext = this;        this.GotFocus += PropertyItemBase_GotFocus;        this.RequestBringIntoView += PropertyItemBase_RequestBringIntoView;        this.AddHandler(PropertyItemsControl.PreparePropertyItemEvent, new PropertyItemEventHandler(this.OnPreparePropertyItemInternal));        this.AddHandler(PropertyItemsControl.ClearPropertyItemEvent, new PropertyItemEventHandler(this.OnClearPropertyItemInternal));    }    /// <summary>    /// Gets or sets the AdvancedOptionsIconProperty.    /// </summary>    public ImageSource AdvancedOptionsIcon    {        get => (ImageSource)GetValue(AdvancedOptionsIconProperty);        set => SetValue(AdvancedOptionsIconProperty, value);    }    /// <summary>    /// Gets or sets the AdvancedOptionsTooltipProperty.    /// </summary>    public object AdvancedOptionsTooltip    {        get => GetValue(AdvancedOptionsTooltipProperty);        set => SetValue(AdvancedOptionsTooltipProperty, value);    }    /// <summary>    /// Gets or sets the definition key to be used in order to determine the editor used or editor definition for the value.    /// </summary>    public object DefinitionKey    {        get => GetValue(DefinitionKeyProperty);        set => SetValue(DefinitionKeyProperty, value);    }    /// <summary>    /// Gets or sets the Description property.    /// </summary>    public string Description    {        get => (string)GetValue(DescriptionProperty);        set => SetValue(DescriptionProperty, value);    }    /// <summary>    /// Gets or sets the DisplayName property.    /// </summary>    public string DisplayName    {        get => (string)GetValue(DisplayNameProperty);        set => SetValue(DisplayNameProperty, value);    }    /// <summary>    /// Gets or sets the editor of the PropertyItem.    /// </summary>    public FrameworkElement? Editor    {        get => (FrameworkElement)GetValue(EditorProperty);        set => SetValue(EditorProperty, value);    }    /// <summary>    /// Gets or sets the text part to highlight in the Property name of the PropertyItem.    /// </summary>    public string? HighlightedText    {        get => (string?)GetValue(HighlightedTextProperty);        set => SetValue(HighlightedTextProperty, value);    }    /// <summary>    /// Gets or sets a value indicating whether the PropertyItem is expanded to show its sub-properties.    /// </summary>    public bool IsExpanded    {        get => (bool)GetValue(IsExpandedProperty);        set => SetValue(IsExpandedProperty, value);    }    /// <summary>    /// Gets or sets a value indicating whether the PropertyItem can be expanded to show its sub-properties.    /// </summary>    public bool IsExpandable    {        get => (bool)GetValue(IsExpandableProperty);        set => SetValue(IsExpandableProperty, value);    }    /// <summary>    /// Gets or sets a value indicating whether the PropertyItem is selected.    /// </summary>    public bool IsSelected    {        get => (bool)GetValue(IsSelectedProperty);        set => SetValue(IsSelectedProperty, value);    }    /// <summary>    /// Gets or sets a value indicating whether the PropertyGrid will be refreshed when the property value changes.    /// 当此属性的值发生改变时，是否强制刷新整个属性网格 (PropertyGrid).    /// </summary>    /// <value>    /// 如果为 <c>true</c>，则当此属性值变化时，PropertyGrid 会重新生成或刷新视图；    /// 如果为 <c>false</c>，则仅更新当前属性的显示值. 默认值为 <c>false</c>.    /// </value>    /// <remarks>    /// <para>    /// <b>使用场景：</b>    /// 此属性主要用于实现属性间的<b>结构性联动</b>.    /// </para>    /// <para>    /// 例如：当你修改一个 Enum 类型的属性（如 "ShapeType" 从 Circle 变为 Rectangle）时，    /// 你可能希望隐藏 "Radius" 属性并显示 "Width" 和 "Height" 属性.    /// 这种情况下，需要将 "ShapeType" 的 <see cref="WillRefreshPropertyGrid"/> 设置为 <c>true</c>，    /// 以便 PropertyGrid 重新计算所有属性的可见性规则（如 <see cref="VisibleToAttribute"/>）.    /// </para>    /// </remarks>    public bool WillRefreshPropertyGrid    {        get => (bool)GetValue(WillRefreshPropertyGridProperty);        set => SetValue(WillRefreshPropertyGridProperty, value);    }    /// <summary>    /// Gets or sets the parent property container.    /// </summary>    internal IPropertyContainer? ParentNode    {        get => this.parentNode;        set => this.parentNode = value;    }    /// <summary>    /// Gets the parent FrameworkElement.    /// </summary>    public FrameworkElement? ParentElement => this.ParentNode as FrameworkElement;    /// <summary>    /// Gets the value container.    /// </summary>    internal ContentControl ValueContainer => this.valueContainer;    /// <summary>    /// Gets or internal sets the level of the PropertyItem in the PropertyGrid hierarchy.    /// </summary>    public int Level { get; internal set; }    /// <summary>    /// Gets the collection of properties.    /// </summary>    public IList Properties    {        get        {            if (this.containerHelper == null)            {                this.containerHelper = new ObjectContainerHelper(this, null);            }            return this.containerHelper.Properties;        }    }    /// <summary>    /// Gets the style applied to the PropertyContainer.    /// </summary>    public Style? PropertyContainerStyle    {        get        {            if (this.ParentNode == null)            {                return null;            }            return this.ParentNode.PropertyContainerStyle;        }    }    /// <summary>    /// Gets or sets a value to containerHelper.    /// </summary>    internal ContainerHelperBase ContainerHelper    {        get        {            return this.containerHelper;        }        set        {            ArgumentNullException.ThrowIfNull(value);            this.containerHelper = value;            this.RaisePropertyChanged(() => this.Properties);        }    }    /// <summary>    /// Gets or sets 当前对象关联的所有可见性控制特性（VisibleByAttribute）集合.    /// </summary>    public List<VisibleToAttribute>? VisibleToAttributes    {        get        {            return this.visibleToAttributes;        }        protected set        {            ArgumentNullException.ThrowIfNull(value);            this.visibleToAttributes = value;            this.RaisePropertyChanged(() => this.VisibleToAttributes);        }    }    /// <summary>    /// Gets or sets 当前对象关联的所有可用性控制特性（EnableByAttribute）集合.    /// </summary>    public List<EnableToAttribute>? EnableToAttributes    {        get        {            return this.enableToAttributes;        }        protected set        {            ArgumentNullException.ThrowIfNull(value);            this.enableToAttributes = value;            this.RaisePropertyChanged(() => this.EnableToAttributes);        }    }    /// <summary>    /// 含有扩展的特性需要即时刷新属性网格（PropertyGrid）以更新属性的可见性或可用性时，此属性返回 true.    /// </summary>    public bool HasExtendedAttributes    {        get        {            if (this.VisibleToAttributes != null && this.VisibleToAttributes.Count > 0)            {                return true;            }            if (this.EnableToAttributes != null && this.EnableToAttributes.Count > 0)            {                return true;            }            return false;        }    }    /// <summary>    /// Gets or sets 小数点位数.    /// </summary>    public int? DecimalPlaces    {        get => this.decimalPlaces;        set => this.decimalPlaces = value;    }    /// <summary>    /// Gets or sets 步长.    /// </summary>    public double? Increment    {        get => this.increment;        set => this.increment = value;    }    /// <summary>    /// Gets or sets 最大值.    /// </summary>    public double? Maximum    {        get => this.maximum;        set => this.maximum = value;    }    /// <summary>    /// Gets or sets 最小值.    /// </summary>    public double? Minimum    {        get => this.minimum;        set => this.minimum = value;    }    /// <inheritdoc/>    Binding? IPropertyContainer.PropertyNameBinding => null;    /// <inheritdoc/>    Binding? IPropertyContainer.PropertyValueBinding => null;    /// <inheritdoc/>    EditorDefinitionBase IPropertyContainer.DefaultEditorDefinition => null;    /// <inheritdoc/>    CategoryDefinitionCollection? IPropertyContainer.CategoryDefinitions => null;    /// <inheritdoc/>    GroupDescription IPropertyContainer.CategoryGroupDescription => null;    /// <inheritdoc/>    List<KeyValuePair<string, PropertyItem>> IPropertyContainer.DependsOnPropertyItemsList => dependsOnPropertyItemsList;    /// <inheritdoc/>    bool IPropertyContainer.IsExpandingNonPrimitiveTypes => isExpandingNonPrimitiveTypes;    /// <inheritdoc/>    Style IPropertyContainer.PropertyContainerStyle => PropertyContainerStyle;    /// <inheritdoc/>    EditorDefinitionCollection? IPropertyContainer.EditorDefinitions    {        get        {            if (this.ParentNode == null)            {                return null;            }            return this.ParentNode.EditorDefinitions;        }    }    /// <inheritdoc/>    PropertyDefinitionCollection? IPropertyContainer.PropertyDefinitions => GetPropertItemPropertyDefinitions();    /// <inheritdoc/>    ContainerHelperBase IPropertyContainer.ContainerHelper => this.ContainerHelper;    /// <inheritdoc/>    bool IPropertyContainer.IsCategorized => this.isPropertyGridCategorized;    /// <inheritdoc/>    bool IPropertyContainer.IsSortedAlphabetically => this.isSortedAlphabetically;    /// <inheritdoc/>    bool IPropertyContainer.AutoGenerateProperties    {        get        {            if (this.ParentNode != null)            {                var propertItemPropertyDefinitions = this.GetPropertItemPropertyDefinitions();                if (propertItemPropertyDefinitions == null || propertItemPropertyDefinitions.Count == 0)                {                    return true;                }                return this.ParentNode.AutoGenerateProperties;            }            return true;        }    }    /// <inheritdoc/>    bool IPropertyContainer.HideInheritedProperties => false;    /// <inheritdoc/>    FilterInfo IPropertyContainer.FilterInfo => default(FilterInfo);    /// <inheritdoc/>    bool? IPropertyContainer.IsPropertyVisible(PropertyDescriptor pd)    {        if (this.parentNode != null)        {            return this.parentNode.IsPropertyVisible(pd);        }        return null;    }    /// <inheritdoc/>    bool? IPropertyContainer.IsPropertyExpandable(PropertyDescriptor pd)    {        if (this.parentNode != null)        {            return this.parentNode.IsPropertyExpandable(pd);        }        return null;    }    public event PropertyChangedEventHandler? PropertyChanged;    internal virtual void OnDefinitionKeyChanged(object oldValue, object newValue)    {    }    protected virtual void OnEditorChanged(FrameworkElement oldValue, FrameworkElement newValue)    {    }    protected virtual void OnIsExpandedChanged(bool oldValue, bool newValue)    {    }    protected virtual void OnIsSelectedChanged(bool oldValue, bool newValue)    {        RaiseItemSelectionChangedEvent();    }    private void RaiseItemSelectionChangedEvent()    {        RaiseEvent(new RoutedEventArgs(ItemSelectionChangedEvent));    }    internal void RaisePropertyChanged<TMember>(Expression<Func<TMember>> propertyExpression)    {        this.Notify(this.PropertyChanged, propertyExpression);    }    internal void RaisePropertyChanged(string name)    {        this.Notify(this.PropertyChanged, name);    }    protected virtual Type? GetPropertyItemType() => null;    protected virtual string GetPropertyItemName() => this.DisplayName;    /// <inheritdoc/>    public override void OnApplyTemplate()    {        base.OnApplyTemplate();        if (this.containerHelper != null)        {            this.containerHelper.ChildrenItemsControl = this.GetTemplateChild(PropertyGrid.PART_PropertyItemsControl) as PropertyItemsControl;        }        this.valueContainer = this.GetTemplateChild(PART_ValueContainer) as ContentControl;    }    /// <inheritdoc/>    protected override void OnMouseDown(MouseButtonEventArgs e)    {        this.IsSelected = true;        if (!this.IsKeyboardFocusWithin)        {            this.Focus();        }        e.Handled = true;    }    /// <inheritdoc/>    protected override AutomationPeer OnCreateAutomationPeer()    {        return new PropertyItemAutomationPeer(this);    }    private void PropertyItemBase_GotFocus(object sender, RoutedEventArgs e)    {        this.IsSelected = true;        e.Handled = true;    }    /// <inheritdoc/>    protected override void OnPropertyChanged(DependencyPropertyChangedEventArgs e)    {        base.OnPropertyChanged(e);        if (ReflectionHelper.IsPublicInstanceProperty(GetType(), e.Property.Name) &&            this.IsLoaded &&            this.parentNode != null &&            !this.parentNode.ContainerHelper.IsCleaning)        {            this.RaisePropertyChanged(e.Property.Name);        }    }    private PropertyDefinitionCollection? GetPropertItemPropertyDefinitions()    {        if (this.ParentNode != null && this.ParentNode.PropertyDefinitions != null)        {            string propertyItemName = GetPropertyItemName();            foreach (PropertyDefinition propertyDefinition in this.ParentNode.PropertyDefinitions)            {                if (propertyDefinition.TargetProperties.Contains(propertyItemName))                {                    return propertyDefinition.PropertyDefinitions;                }                Type? propertyItemType = this.GetPropertyItemType();                if (propertyItemType == null)                {                    continue;                }                foreach (object targetProperty in propertyDefinition.TargetProperties)                {                    Type? type = targetProperty as Type;                    if (type != null && type.IsAssignableFrom(propertyItemType))                    {                        return propertyDefinition.PropertyDefinitions;                    }                }            }        }        return null;    }    private void OnPreparePropertyItemInternal(object sender, PropertyItemEventArgs args)    {        args.PropertyItem.Level = Level + 1;        this.containerHelper?.PrepareChildrenPropertyItem(args.PropertyItem, args.Item);        args.Handled = true;    }    private void OnClearPropertyItemInternal(object sender, PropertyItemEventArgs args)    {        this.containerHelper?.ClearChildrenPropertyItem(args.PropertyItem, args.Item);        args.PropertyItem.Level = 0;        args.Handled = true;    }    private void PropertyItemBase_RequestBringIntoView(object sender, RequestBringIntoViewEventArgs e)    {        e.Handled = true;    }    private static void OnDefinitionKeyChanged(DependencyObject o, DependencyPropertyChangedEventArgs e)    {        if (o is PropertyItemBase propertyItemBase)        {            propertyItemBase.OnDefinitionKeyChanged(e.OldValue, e.NewValue);        }    }    private static void OnEditorChanged(DependencyObject o, DependencyPropertyChangedEventArgs e)    {        if (o is PropertyItemBase propertyItem)        {            propertyItem.OnEditorChanged((FrameworkElement)e.OldValue, (FrameworkElement)e.NewValue);        }    }    private static void OnIsExpandedChanged(DependencyObject o, DependencyPropertyChangedEventArgs e)    {        if (o is PropertyItemBase propertyItemBase)        {            propertyItemBase.OnIsExpandedChanged((bool)e.OldValue, (bool)e.NewValue);        }    }    private static void OnIsSelectedChanged(DependencyObject o, DependencyPropertyChangedEventArgs e)    {        if (o is PropertyItemBase propertyItemBase)        {            propertyItemBase.OnIsSelectedChanged((bool)e.OldValue, (bool)e.NewValue);        }    }}